	if _, err := raw.Exec(`INSERT INTO resources_fts (rowid, id, resource_type, content) VALUES (1, 'shared', 'biz', '{"kind":"biz","name":"legacy restaurant"}')`); err != nil {
		raw.Close()
		t.Fatalf("seed stale resources_fts row: %v", err)
	}
